/// @dev precondition - The caller must have the ASSET_ADMIN_ROLE.
function setMinBidUsdValue(
  uint88 minBidUsdValue
) external onlyRole(Roles.ASSET_ADMIN_ROLE) {
  _setMinBidUsdValue(minBidUsdValue);
}

